import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"2. Production (Distributeur)","description":"","frontmatter":{"title":"2. Production (Distributeur)"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md","filePath":"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"}'),r={name:"docs/fr/advertisers/dedicated-email/2-creation-distributeur.md"};function n(o,e,d,l,u,c){return i(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="etape-2-production-co-branding" tabindex="-1">Étape 2 : Production &amp; Co-branding <a class="header-anchor" href="#etape-2-production-co-branding" aria-label="Permalink to &quot;Étape 2 : Production &amp; Co-branding&quot;">​</a></h1><p>Une fois votre brief envoyé, c&#39;est le distributeur qui prend le relais pour concevoir l&#39;email.</p><hr><h2 id="pourquoi-ce-n-est-pas-vous-qui-creez-l-email" tabindex="-1">Pourquoi ce n&#39;est pas vous qui créez l&#39;email ? <a class="header-anchor" href="#pourquoi-ce-n-est-pas-vous-qui-creez-l-email" aria-label="Permalink to &quot;Pourquoi ce n&#39;est pas vous qui créez l&#39;email ?&quot;">​</a></h2><p><strong>La puissance de l&#39;endorsement (recommandation).</strong></p><p>L&#39;objectif n&#39;est pas d&#39;envoyer une publicité brute, mais une recommandation de la part d&#39;un partenaire de confiance. Les abonnés du distributeur lui font confiance — pour maximiser le taux d&#39;ouverture et de clic, l&#39;email doit respecter les codes graphiques et le ton habituel de la newsletter qu&#39;ils reçoivent chaque semaine.</p><hr><h2 id="a-quoi-va-ressembler-votre-campagne" tabindex="-1">À quoi va ressembler votre campagne ? <a class="header-anchor" href="#a-quoi-va-ressembler-votre-campagne" aria-label="Permalink to &quot;À quoi va ressembler votre campagne ?&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">✅ Le résultat attendu (Natif)</th><th style="text-align:left;">❌ Ce qui est évité (Full Brand)</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Header partenaire</strong> — Logo et menu du distributeur en haut, pour rassurer l&#39;abonné</td><td style="text-align:left;">Email 100% aux couleurs de votre site, sans mention du partenaire</td></tr><tr><td style="text-align:left;"><strong>Édito d&#39;intro</strong> — Le distributeur rédige une phrase d&#39;accroche (<em>&quot;Notre coup de cœur…&quot;</em>)</td><td style="text-align:left;">Absence de contextualisation par le distributeur</td></tr><tr><td style="text-align:left;"><strong>Vos assets</strong> — Visuels et offre intégrés au centre, avec les polices et boutons du partenaire</td><td style="text-align:left;">Dissonance cognitive : l&#39;abonné ne comprend pas pourquoi il reçoit cet email</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Évitez le Full Brand</p><p>Un email Full Brand sans mention du partenaire perturbe l&#39;abonné, augmente les désabonnements et <strong>fait chuter la performance</strong>. Le co-branding natif n&#39;est pas une contrainte — c&#39;est ce qui rend le format efficace.</p></div><hr><h2 id="le-flux-de-production" tabindex="-1">Le flux de production <a class="header-anchor" href="#le-flux-de-production" aria-label="Permalink to &quot;Le flux de production&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Conception</h3><p>Le distributeur (ou le Studio getinside) assemble l&#39;email en utilisant les éléments de votre brief — visuels, offre, wording.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Intégration Technique</h3><p>Les liens de tracking dynamiques sont générés et insérés. Le code HTML est optimisé pour la délivrabilité et le responsive.</p></div></div><div class="gi-step"><div class="gi-step-num done">3</div><div class="gi-step-body"><h3>Review Interne</h3><p>L&#39;équipe getinside vérifie la qualité technique avant de soumettre le résultat à votre validation.</p></div></div><hr><h2 id="vos-liens-sont-dynamiques" tabindex="-1">Vos liens sont dynamiques <a class="header-anchor" href="#vos-liens-sont-dynamiques" aria-label="Permalink to &quot;Vos liens sont dynamiques&quot;">​</a></h2><p>Vous avez fait une erreur dans le brief ? Vous changez de landing page à la dernière minute ?</p><div class="tip custom-block"><p class="custom-block-title">Pas de panique — modifiez à tout moment</p><p>Les liens de tracking email sont <strong>dynamiques</strong>, comme les QR codes getinside. Vous pouvez modifier l&#39;URL de destination finale à tout moment dans l&#39;onglet <strong>&quot;Configuration et Suivi&quot;</strong> de votre campagne — même si le distributeur a déjà intégré le lien.</p></div><hr><h2 id="et-ensuite" tabindex="-1">Et ensuite ? <a class="header-anchor" href="#et-ensuite" aria-label="Permalink to &quot;Et ensuite ?&quot;">​</a></h2><p>Dès que la création est prête et validée techniquement, vous recevez une notification pour passer à la validation du BAT.</p><p>→ Étape suivante : <a href="./3-validation-diffusion.html">Validation &amp; Diffusion</a></p>',23)])])}const v=t(r,[["render",n]]);export{m as __pageData,v as default};
